  --agent-name <name>     Agent name (default: agent8888)\n\
  --env-file <path>       Load environment from file\n\
  --env KEY=VAL           Set environment variable\n\
  --mock-quota <spec>     Mock quota specification\n\
  --model <ref>           Default model reference\n\
  --probe curl            Enable curl-based probing\n\
  --probe-timeout-secs <n> Probe timeout (default: 3)\n\
  --quota-min-req <n>     Minimum remaining requests\n\
  --quota-min-tok <n>     Minimum remaining tokens\n\
  --ignore-process-env    Ignore process environment\n\
  -h, --help              Show this help"
