    log::info!("Starting Ollama Emulator on port {}", args.port);

    // Initialize lifecycle
    let lifecycle = initialize_lifecycle(&args);

    // Create shared state
    let state = Arc::new(RwLock::new(OllamaEmulatorState {
        lifecycle,
        quota_selection: None,
        models: vec![],
    }));

    // Initialize models from lifecycle
    {
        let mut state = state.write().await;
        if let Some(ref lc) = state.lifecycle {
            state.models = vec![OllamaModel {
                name: lc.route.upstream_model_id.clone(),
