    let exe_basename = std::path::Path::new(&exe_name)
        .file_name()
        .and_then(|s| s.to_str())
        .unwrap_or("ollama_emulator")
... [CONTENT TRUNCATED] ...
                        .ok_or("missing value for --model")?,
                );
