/// Indexed trait for position-based access
pub trait Indexed<T> {
    fn get(&self, index: usize) -> Option<&T>;
    fn len(&self) -> usize;
    fn is_empty(&self) -> bool {
        self.len() == 0
    }
}

impl<T> Indexed<T> for Vec<T> {
    fn get(&self, index: usize) -> Option<&T> {
        self.as_slice().get(index)
    }
    fn len(&self) -> usize {
        Vec::len(self)
    }
}

impl<T> Indexed<T> for [T] {
    fn get(&self, index: usize) -> Option<&T> {
        self.get(index)
    }
    fn len(&self) -> usize {
        self.len()
    }
}

