{"content":"// Model Mux Precedence Configuration
// User-defined precedence for env projection vs keymux

/// Precedence mode for provider selection
#[derive(Debug, Clone, PartialEq)]
pub enum PrecedenceMode {
    /// Env projection first, then keymux refinement
    EnvFirst,

    /// Keymux first, then env projection fallback
    KeymuxFirst,

    /// Balanced: both systems vote, weighted decision
    Balanced { 
        env_weight: f32, 
        keymux_weight: f32 
    },

    /// Custom user-defined precedence rules
    Custom(Vec<PrecedenceRule>),
}

impl Default for PrecedenceMode {
    fn default() -> Self {
        PrecedenceMode::EnvFirst
    }
}

impl PrecedenceMode {
    /// Create balanced precedence with equal weights
    pub fn balanced() -> Self {
        PrecedenceMode::Balanced { 
            env_weight: 0.5, 
            keymux_weight: 0.5 
        }
    }

    /// Validate weights sum to 1.0
    pub fn validate(&self) -> bool {
        match self {
            PrecedenceMode::Balanced { env_weight, keymux_weight } => {
                (env_weight + keymux_weight - 1.0).abs() < 0.001
            }
            PrecedenceMode::Custom(rules) => {
                rules.iter().all(|r| r.validate())
            }
            _ => true,
        }
    }
}

/// Precedence rule for custom configuration
#[derive(Debug, Clone, PartialEq)]
pub struct PrecedenceRule {
    /// Provider ID to match (e.g., "kilo_code", "moonshot")
    pub provider_id: String,

    /// Precedence for this provider
    pub precedence: ProviderPrecedence,

    /// Optional weight for balanced mode
    pub weight: Option<f32>,
}

impl PrecedenceRule {
    pub fn new(provider_id: &str, precedence: ProviderPrecedence) -> Self {
        Self {
            provider_id: provider_id.to_string(),
            precedence,
            weight: None,
        }
    }

    pub fn with_weight(mut self, weight: f32) -> Self {
        self.weight = Some(weight);
        self
    }

    pub fn validate(&self) -> bool {
        !self.provider_id.is_empty() && 
        self.weight.map_or(true, |w| w >= 0.0 && w <= 1.0)
    }
}

/// Provider-specific precedence
#[derive(Debug, Clone, PartialEq)]
pub enum ProviderPrecedence {
    /// Use env projection only
    EnvOnly,

    /// Use keymux only
    KeymuxOnly,

    /// Use env first, keymux as fallback
    EnvFirst,

    /// Use keymux first, env as fallback
    KeymuxFirst,

    /// Use balanced weighted decision
    Balanced { weight: f32 },
}

impl ProviderPrecedence {
    pub fn env_only() -> Self {
        ProviderPrecedence::EnvOnly
    }

    pub fn keymux_only() -> Self {
        ProviderPrecedence::KeymuxOnly
    }

    pub fn balanced(weight: f32) -> Self {
        ProviderPrecedence::Balanced { weight }
    }
}

/// Decision source for routing
#[derive(Debug, Clone, PartialEq)]
pub enum DecisionSource {
    /// Decision from env projection
    EnvProjection,

    /// Decision from keymux
    Keymux,

    /// Weighted combination
    Balanced { confidence: f32 },

    /// Fallback decision
    Fallback,
}

/// Routing decision result
#[derive(Debug, Clone)]
pub struct RoutingDecision {
    /// Selected provider ID
    pub provider_id: String,

    /// Source of decision
    pub source: DecisionSource,

    /// Confidence score (0.0 - 1.0)
    pub confidence: f32,

    /// Reason for decision
    pub reason: String,
}

impl RoutingDecision {
    pub fn new(provider_id: &str, source: DecisionSource, confidence: f32, reason: &str) -> Self {
        Self {
            provider_id: provider_id.to_string(),
            source,
            confidence,
            reason: reason.to_string(),
        }
    }

    pub fn from_env(provider_id: &str, confidence: f32) -> Self {
        Self::new(
            provider_id, 
            DecisionSource::EnvProjection, 
            confidence,
            "Selected via env projection"
        )
    }

    pub fn from_keymux(provider_id: &str, confidence: f32) -> Self {
        Self::new(
            provider_id, 
            DecisionSource::Keymux, 
            confidence,
            "Selected via keymux"
        )
    }

    pub fn balanced(provider_id: &str, confidence: f32) -> Self {
        Self::new(
            provider_id, 
            DecisionSource::Balanced { confidence }, 
            confidence,
            "Selected via balanced weighted decision"
        )
    }
}

/// Model mux configuration
#[derive(Debug, Clone)]
pub struct ModelmuxConfig {
    /// Port for model mux (default: 8888)
    pub port: u16,

    /// Agent name (default: "agent8888")
    pub agent_name: String,

    /// Precedence mode
    pub precedence: PrecedenceMode,

    /// Quota policy
    pub quota_policy: QuotaPolicy,

    /// Enable logging
    pub enable_logging: bool,
}

impl Default for ModelmuxConfig {
    fn default() -> Self {
        Self {
            port: 8888,
            agent_name: "agent8888".to_string(),
            precedence: PrecedenceMode::default(),
            quota_policy: QuotaPolicy::FreeFirst,
            enable_logging: true,
        }
    }
}

impl ModelmuxConfig {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn with_port(mut self, port: u16) -> Self {
        self.port = port;
        self
    }

    pub fn with_agent_name(mut self, name: &str) -> Self {
        self.agent_name = name.to_string();
        self
    }

    pub fn with_precedence(mut self, precedence: PrecedenceMode) -> Self {
        self.precedence = precedence;
        self
    }

    pub fn with_quota_policy(mut self, policy: QuotaPolicy) -> Self {
        self.quota_policy = policy;
        self
    }

    pub fn validate(&self) -> bool {
        self.port > 0 && 
        self.port < 65536 &&
        !self.agent_name.is_empty() &&
        self.precedence.validate()
    }
}

/// Quota policy for provider selection
#[derive(Debug, Clone, PartialEq)]
pub enum QuotaPolicy {
    /// Free tier first, then paid fallback
    FreeFirst,

    /// Lowest cost first
    LowestCost,

    /// Highest quota first
    HighestQuota,

    /// Custom policy
    Custom(String),
}

impl Default for QuotaPolicy {
    fn default() -> Self {
        QuotaPolicy::FreeFirst
    }
}

