mod tests {
    use super::*;

    #[test]
    fn test_precedence_mode_default() {
        let mode = PrecedenceMode::default();
        assert_eq!(mode, PrecedenceMode::EnvFirst);
    }

    #[test]
    fn test_precedence_mode_balanced() {
        let mode = PrecedenceMode::balanced();
        assert!(mode.validate());

        if let PrecedenceMode::Balanced { env_weight, keymux_weight } = mode {
            assert_eq!(env_weight, 0.5);
            assert_eq!(keymux_weight, 0.5);
        } else {
            panic!("Expected Balanced mode");
        }
    }

    #[test]
    fn test_precedence_rule_validation() {
        let rule = PrecedenceRule::new("kilo_code", ProviderPrecedence::EnvFirst);
        assert!(rule.validate());

        let rule_with_weight = rule.clone().with_weight(0.8);
        assert!(rule_with_weight.validate());

        let invalid_rule = rule.clone().with_weight(1.5);
        assert!(!invalid_rule.validate());
    }

    #[test]
    fn test_routing_decision_from_env() {
        let decision = RoutingDecision::from_env("kilo_code", 0.95);
        assert_eq!(decision.provider_id, "kilo_code");
        assert_eq!(decision.source, DecisionSource::EnvProjection);
        assert_eq!(decision.confidence, 0.95);
    }

    #[test]
    fn test_routing_decision_from_keymux() {
        let decision = RoutingDecision::from_keymux("moonshot", 0.85);
        assert_eq!(decision.provider_id, "moonshot");
        assert_eq!(decision.source, DecisionSource::Keymux);
    }

    #[test]
    fn test_routing_decision_balanced() {
        let decision = RoutingDecision::balanced("deepseek", 0.90);
        assert_eq!(decision.provider_id, "deepseek");
        assert!(matches!(decision.source, DecisionSource::Balanced { .. }));
    }

    #[test]
    fn test_modelmux_config_default() {
        let config = ModelmuxConfig::default();
        assert_eq!(config.port, 8888);
        assert_eq!(config.agent_name, "agent8888");
        assert_eq!(config.precedence, PrecedenceMode::EnvFirst);
        assert_eq!(config.quota_policy, QuotaPolicy::FreeFirst);
        assert!(config.enable_logging);
    }

    #[test]
    fn test_modelmux_config_builder() {
        let config = ModelmuxConfig::new()
            .with_port(9999)
            .with_agent_name("custom_agent")
            .with_precedence(PrecedenceMode::balanced())
            .with_quota_policy(QuotaPolicy::LowestCost);

        assert_eq!(config.port, 9999);
        assert_eq!(config.agent_name, "custom_agent");
        assert!(matches!(config.precedence, PrecedenceMode::Balanced { .. }));
        assert_eq!(config.quota_policy, QuotaPolicy::LowestCost);
    }

    #[test]
    fn test_modelmux_config_validation() {
        let valid_config = ModelmuxConfig::default();
        assert!(valid_config.validate());

        let invalid_port = ModelmuxConfig::new().with_port(0);
        assert!(!invalid_port.validate());

        let invalid_name = ModelmuxConfig::new().with_agent_name("");
        assert!(!invalid_name.validate());
    }

    #[test]
    fn test_quota_policy_default() {
        let policy = QuotaPolicy::default();
        assert_eq!(policy, QuotaPolicy::FreeFirst);
    }
